Ini implementasi Observer Pattern yang solid untuk Python. Menggunakan `abc` untuk interface yang ketat dan `typing` untuk type safety.

```python
from abc import ABC, abstractmethod
from typing import List, Any
import logging

# Konfigurasi Logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject', *args: Any, **kwargs: Any) -> None:
        pass

class Subject:
    def __init__(self) -> None:
        self._observers: List[Observer] = []
        self._state: Any = None

    def attach(self, observer: Observer) -> None:
        if observer not in self._observers:
            self._observers.append(observer)

    def detach(self, observer: Observer) -> None:
        try:
            self._observers.remove(observer)
        except ValueError:
            logger.warning(f"Observer {observer} tidak ditemukan untuk dihapus.")

    def notify(self, *args: Any, **kwargs: Any) -> None:
        for observer in self._observers:
            try:
                observer.update(self, *args, **kwargs)
            except Exception as e:
                # Critical: Jangan biarkan satu observer error menghentikan notifikasi ke lainnya
                logger.error(f"Error pada observer {observer.__class__.__name__}: {e}")

    def set_state(self, state: Any) -> None:
        self._state = state
        self.notify(event="state_change", new_state=state)

    def get_state(self) -> Any:
        return self._state

class ConcreteObserver(Observer):
    def __init__(self, name: str) -> None:
        self.name = name

    def update(self, subject: Subject, *args: Any, **kwargs: Any) -> None:
        logger.info(f"[{self.name}] Menerima notifikasi: {kwargs}")
        # Logic pemrosesan data di sini

# Usage Example
if __name__ == "__main__":
    subject = Subject()
    obs1 = ConcreteObserver("SecurityMonitor")
    obs2 = ConcreteObserver("LogAnalyzer")

    subject.attach(obs1)
    subject.attach(obs2)

    subject.set_state({"status": "critical", "ip": "192.168.1.1"})
```

### Catatan Teknis & Keamanan:

1.  **Exception Handling:** Pada method `notify`, saya membungkus pemanggilan observer dengan `try-except`. Ini krusial. Jika satu observer crash (misalnya karena bug atau timeout DB), subjek tetap bisa memberi tahu observer lain. Ini mencegah *Single Point of Failure* dalam alur event.
2.  **Blocking Operations:** Pastikan method `update` pada observer tidak melakukan operasi berat (I/O blocking, heavy computation) secara sinkron. Jika digunakan di server production (seperti environment PT Sherif Network), pertimbangkan menggunakan `asyncio` atau melempar task ke queue worker agar subjek tidak terhambat.
3.  **Memory Leaks:** Perhatikan referensi sirkular. Jika `Subject` memegang referensi kuat ke `Observer` dan sebaliknya, garbage collector mungkin gagal membersihkan memori. Gunakan `weakref` jika diperlukan untuk skalabilitas tinggi.

Gunakan pola ini untuk decoupling logic, misalnya memisahkan validasi input, logging audit, dan notifikasi alert keamanan.

# Recursive Dictionary Diff Function

Berikut implementasi lengkap untuk membandingkan dua dictionary secara rekursif:

```python
from typing import Any, Dict, List, Tuple, Union

class DictDiff:
    """Class to represent differences between two dictionaries"""

    def __init__(self):
        self.added: List[str] = []      # Keys in dict2 but not in dict1
        self.removed: List[str] = []    # Keys in dict1 but not in dict2
        self.modified: List[str] = []   # Keys with different values
        self.changed: Dict[str, Tuple[Any, Any]] = {}  # {key: (old_value, new_value)}

    def __bool__(self):
        return bool(self.added or self.removed or self.modified)

    def __repr__(self):
        return f"DictDiff(added={len(self.added)}, removed={len(self.removed)}, modified={len(self.modified)})"


def diff_dicts(dict1: Dict[str, Any], dict2: Dict[str, Any], path: str = "") -> DictDiff:
    """
    Recursively compare two dictionaries and return differences.

    Args:
        dict1: First dictionary (baseline/old)
        dict2: Second dictionary (new)
        path: Current key path for nested tracking

    Returns:
        DictDiff object containing all differences
    """
    result = DictDiff()

    all_keys = set(dict1.keys()) | set(dict2.keys())

    for key in all_keys:
        current_path = f"{path}.{key}" if path else key

        # Key only in dict1 (removed)
        if key in dict1 and key not in dict2:
            result.removed.append(current_path)
            result.changed[current_path] = (dict1[key], None)

        # Key only in dict2 (added)
        elif key not in dict1 and key in dict2:
            result.added.append(current_path)
            result.changed[current_path] = (None, dict2[key])

        # Key in both - check values
        else:
            val1, val2 = dict1[key], dict2[key]

            # Both are dicts - recurse
            if isinstance(val1, dict) and isinstance(val2, dict):
                nested_diff = diff_dicts(val1, val2, current_path)
                result.added.extend(nested_diff.added)
                result.removed.extend(nested_diff.removed)
                result.modified.extend(nested_diff.modified)
                result.changed.update(nested_diff.changed)

            # Values differ
            elif val1 != val2:
                result.modified.append(current_path)
                result.changed[current_path] = (val1, val2)

    return result


def diff_dicts_simple(dict1: Dict, dict2: Dict) -> Dict[str, Any]:
    """
    Simplified version returning plain dictionary with differences.

    Returns:
        {
            'added': {key: value},
            'removed': {key: value},
            'modified': {key: {'old': val1, 'new': val2}}
        }
    """
    result = {'added': {}, 'removed': {}, 'modified': {}}

    all_keys = set(dict1.keys()) | set(dict2.keys())

    for key in all_keys:
        if key in dict1 and key not in dict2:
            result['removed'][key] = dict1[key]
        elif key not in dict1 and key in dict2:
            result['added'][key] = dict2[key]
        elif dict1[key] != dict2[key]:
            # Check for nested dicts
            if isinstance(dict1[key], dict) and isinstance(dict2[key], dict):
                nested = diff_dicts_simple(dict1[key], dict2[key])
                for diff_type in ['added', 'removed', 'modified']:
                    if nested[diff_type]:
                        result[diff_type][key] = nested[diff_type]
            else:
                result['modified'][key] = {'old': dict1[key], 'new': dict2[key]}

    return result


# ============ USAGE EXAMPLES ============

if __name__ == "__main__":
    # Example 1: Basic diff
    dict1 = {
        'name': 'John',
        'age': 25,
        'email': 'john@example.com'
    }

    dict2 = {
        'name': 'John',
        'age': 26,
        'phone': '123-456'
    }

    diff = diff_dicts(dict1, dict2)
    print(f"Added: {diff.added}")
    print(f"Removed: {diff.removed}")
    print(f"Modified: {diff.modified}")
    print(f"Changes: {diff.changed}")

    # Example 2: Nested dictionaries
    config_old = {
        'database': {
            'host': 'localhost',
            'port': 3306,
            'credentials': {
                'user': 'admin',
                'pass': 'secret123'
            }
        },
        'cache': {
            'enabled': True,
            'ttl': 3600
        }
    }

    config_new = {
        'database': {
            'host': '192.168.1.100',
            'port': 3306,
            'credentials': {
                'user': 'admin',
                'pass': 'newpass456'
            }
        },
        'cache': {
            'enabled': False
        },
        'logging': {
            'level': 'DEBUG'
        }
    }

    diff = diff_dicts(config_old, config_new)
    print(f"\nNested Diff: {diff}")
    print(f"Full Changes: {diff.changed}")

    # Example 3: Simple version
    simple_diff = diff_dicts_simple(config_old, config_new)
    print(f"\nSimple Diff: {simple_diff}")
```

