SENSITIVE_KEYS = {'password', 'pass', 'secret', 'token', 'api_key'}

def mask_value(key: str, value: Any) -> str:
    if any(s in key.lower() for s in SENSITIVE_KEYS):
        return '***REDACTED***'
    return value
